public class PrimitivePassByValue {

    static void swap(int a, int b) {
        int temp = a;
        a = b;
        b = temp;
        System.out.println("Inside swap: a=" + a + ", b=" + b);
    }

    public static void main(String[] args) {
        int x = 10, y = 20;
        System.out.println("Before: x=" + x + ", y=" + y);
        swap(x, y);
        System.out.println("After : x=" + x + ", y=" + y); // still 10, 20
    }
}
// Output:
// Before: x=10, y=20
// Inside swap: a=20, b=10
// After : x=10, y=20  <- x and y UNCHANGED

import java.util.*;

public class ObjectPassByValue {

    static void addElement(List<String> list, String item) {
        list.add(item);          // WORKS: mutating through the reference copy
    }

    static void replaceList(List<String> list) {
        list = new ArrayList<>(); // DOESN'T WORK: only reassigns local copy
        list.add("new item");
    }

    public static void main(String[] args) {
        List<String> myList = new ArrayList<>(Arrays.asList("a", "b"));

        addElement(myList, "c");
        System.out.println("After addElement: " + myList); // [a, b, c]

        replaceList(myList);
        System.out.println("After replaceList: " + myList); // still [a, b, c]
    }
}
// Output:
// After addElement: [a, b, c]
// After replaceList: [a, b, c]  <- replaceList had no effect

public class StringPassByValue {

    static void tryToModify(String s) {
        s = s + " World";  // creates new String object, reassigns local 's'
        System.out.println("Inside method: " + s); // Hello World
    }

    static void tryToModifySB(StringBuilder sb) {
        sb.append(" World"); // mutates the SAME StringBuilder object
        System.out.println("Inside method: " + sb); // Hello World
    }

    public static void main(String[] args) {
        String str = "Hello";
        tryToModify(str);
        System.out.println("After tryToModify: " + str); // Hello (unchanged)

        StringBuilder sb = new StringBuilder("Hello");
        tryToModifySB(sb);
        System.out.println("After tryToModifySB: " + sb); // Hello World (changed!)
    }
}
// Output:
// Inside method: Hello World
// After tryToModify: Hello
// Inside method: Hello World
// After tryToModifySB: Hello World

import java.util.Arrays;

public class ArrayPassByValue {

    // Works: mutating array elements through the reference
    static void doubleElements(int[] arr) {
        for (int i = 0; i < arr.length; i++) {
            arr[i] *= 2;  // modifies element at arr's heap address
        }
    }

    // Doesn't work: reassigning the array parameter
    static void replaceArray(int[] arr) {
        arr = new int[]{100, 200, 300}; // local reassign only
    }

    // Works: returning a new array
    static int[] createDoubled(int[] arr) {
        int[] result = new int[arr.length];
        for (int i = 0; i < arr.length; i++) result[i] = arr[i] * 2;
        return result;
    }

    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 5};

        doubleElements(nums);
        System.out.println(Arrays.toString(nums)); // [2, 4, 6, 8, 10]

        replaceArray(nums);
        System.out.println(Arrays.toString(nums)); // [2, 4, 6, 8, 10] unchanged

        int[] doubled = createDoubled(nums);
        System.out.println(Arrays.toString(doubled)); // [4, 8, 12, 16, 20]
    }
}

// Java can't pass primitives by reference — workarounds:

public class MultipleReturnValues {

    // Pattern 1: Single-element array as output parameter
    static void divideAndRemainder(int a, int b, int[] quotient, int[] remainder) {
        quotient[0]  = a / b;
        remainder[0] = a % b;
    }

    // Pattern 2: Return a small result object (preferred)
    record DivResult(int quotient, int remainder) {}

    static DivResult divideAndRemainderOOP(int a, int b) {
        return new DivResult(a / b, a % b);
    }

    // Pattern 3: int[] return (least readable but common in competitive programming)
    static int[] divideAndRemainderArray(int a, int b) {
        return new int[]{a / b, a % b};
    }

    public static void main(String[] args) {
        // Pattern 1 usage
        int[] q = new int[1], r = new int[1];
        divideAndRemainder(17, 5, q, r);
        System.out.println("Quotient=" + q[0] + " Remainder=" + r[0]);

        // Pattern 2 usage (cleanest)
        DivResult res = divideAndRemainderOOP(17, 5);
        System.out.println("Quotient=" + res.quotient() + " Remainder=" + res.remainder());

        // Pattern 3
        int[] arr = divideAndRemainderArray(17, 5);
        System.out.println("Quotient=" + arr[0] + " Remainder=" + arr[1]);
    }
}
// Output (all three):
// Quotient=3 Remainder=2

