import java.util.Arrays;

public class Q10 {
    public static int[][] shallowCopy(int[][] matrix) {
        int[][] copy = new int[matrix.length][];
        for (int i = 0; i < matrix.length; i++) {
            copy[i] = matrix[i]; // shared reference to same row
        }
        return copy;
    }

    public static int[][] deepCopy(int[][] matrix) {
        int[][] copy = new int[matrix.length][];
        for (int i = 0; i < matrix.length; i++) {
            copy[i] = Arrays.copyOf(matrix[i], matrix[i].length); // new row
        }
        return copy;
    }

    public static void main(String[] args) {
        int[][] original = {{1, 2}, {3, 4}};

        int[][] shallow = shallowCopy(original);
        shallow[0][0] = 99;
        System.out.println(original[0][0]); // 99 — shared inner array!

        int[][] deep = deepCopy(original);
        deep[0][0] = 77;
        System.out.println(original[0][0]); // 99 — unchanged, independent copy
    }
}

