import java.util.*;

public class Q14 {
    static class Person {
        String name;
        Person(String name) { this.name = name; }
        public String toString() { return name; }
    }

    public static List<Person> shallowCopyList(List<Person> list) {
        return new ArrayList<>(list); // new list, same Person objects
    }

    public static List<Person> deepCopyList(List<Person> list) {
        List<Person> copy = new ArrayList<>();
        for (Person p : list) copy.add(new Person(p.name)); // new Person objects
        return copy;
    }

    public static void main(String[] args) {
        List<Person> original = new ArrayList<>(List.of(new Person("Alice"), new Person("Bob")));

        List<Person> shallow = shallowCopyList(original);
        shallow.get(0).name = "CHANGED";
        System.out.println(original.get(0).name); // CHANGED — same Person object

        List<Person> deep = deepCopyList(original);
        deep.get(0).name = "DEEP_CHANGED";
        System.out.println(original.get(0).name); // CHANGED — deep copy is independent
    }
}

