public class Q17 {
    public static String longestCommonPrefix(String[] strs) {
        if (strs == null || strs.length == 0) return "";
        String[] result = {strs[0]};
        findPrefix(strs, 1, result);
        return result[0];
    }
    static void findPrefix(String[] strs, int idx, String[] result) {
        if (idx >= strs.length || result[0].isEmpty()) return;
        while (!strs[idx].startsWith(result[0])) {
            result[0] = result[0].substring(0, result[0].length() - 1);
            if (result[0].isEmpty()) return;
        }
        findPrefix(strs, idx + 1, result);
    }
    public static void main(String[] args) {
        System.out.println(longestCommonPrefix(new String[]{"flower","flow","flight"})); // fl
        System.out.println(longestCommonPrefix(new String[]{"dog","racecar","car"})); // ""
    }
}

