import java.util.*;

public class Q20 {
    static class ObjectPool<T> {
        private Queue<T> pool = new LinkedList<>();

        public void populate(List<T> objects) {
            pool.addAll(objects);
        }

        public T acquire() {
            return pool.poll();
        }

        public void release(T obj) {
            pool.offer(obj);
        }

        public int available() { return pool.size(); }
    }

    public static void main(String[] args) {
        ObjectPool<StringBuilder> pool = new ObjectPool<>();
        pool.populate(List.of(new StringBuilder(), new StringBuilder()));
        StringBuilder a = pool.acquire();
        a.append("Hello");
        pool.release(a);
        StringBuilder b = pool.acquire(); // same object from queue
        System.out.println(b.toString()); // Hello — mutation persists!
        System.out.println(pool.available()); // 1 (one still in pool)
    }
}
